#include<bits/stdc++.h>
using namespace std;
long long n,m,s;
long long w[200010],v[200010];
long long flag[200010],s1[200010],s2[200010];
long long l[200010],r[200010];
long long check(long long x)
{
    for(long long i=1;i<=n;i++)
    {
        flag[i]=(w[i]>=x);
        s2[i]=s2[i-1]+flag[i];
        s1[i]=s1[i-1]+flag[i]*v[i];
    }
    long long sum=0;
    for(long long i=1;i<=m;i++)
    {
        sum+=(s2[r[i]]-s2[l[i]-1])*(s1[r[i]]-s1[l[i]-1]);
    }
    return sum-s;
}
int main()
{
    scanf("%lld%lld%lld",&n,&m,&s);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&w[i],&v[i]);
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld",&l[i],&r[i]);
    }
    long long l1=0,r1=1e9,best=s;
    while(l1<=r1)
    {
        long long mid=(l1+r1)/2;
        long long tmp=check(mid);
        if(tmp<0)
        {
            r1=mid-1;
        }
        else
        {
            l1=mid+1;
        }
        best=min(best,abs(tmp));
    }
    printf("%lld",best);
    return 0;
}
